from collections import deque
from typing import List


class Solution:
    def catFishCardGame(self, cardA: List[int], cardB: List[int]) -> int:
        # 用队列维护双方手牌，队首出牌，队尾收牌
        a = deque(cardA)
        b = deque(cardB)

        # 桌面牌堆，按“从底到顶”存储
        table = []

        # pos[x] 维护点数 x 在桌面上的出现位置栈
        pos = [[] for _ in range(14)]

        # 0 表示甲回合，1 表示乙回合
        turn = 0
        moves = 0

        while True:
            cur = a if turn == 0 else b
            other = b if turn == 0 else a

            # 回合开始时无牌可出，游戏立即结束
            if not cur:
                if other:
                    # 对方获胜，返回对方手牌最上方
                    return other[0]
                # 双方都没牌，平局
                return 0 if not table else table[-1]

            # 出牌
            x = cur.popleft()
            moves += 1

            # 记录出牌前桌面是否为空，供 J 特效判断
            had_table = len(table) > 0

            # 放到桌面顶端
            old_same = pos[x][-1] if pos[x] else -1
            table.append(x)
            pos[x].append(len(table) - 1)

            captured = False

            # J 特效优先：若出的是 J 且出牌前桌面非空，则收走整桌
            if x == 11 and had_table:
                start = 0
                captured = True
            # 否则如果之前有相同点数牌，收走该区间
            elif old_same != -1:
                start = old_same
                captured = True

            if captured:
                # 收走 table[start:]，顺序保持为桌面从下到上
                gained = table[start:]

                # 同步弹出位置栈中对应的下标
                for i in range(len(table) - 1, start - 1, -1):
                    v = table[i]
                    pos[v].pop()

                # 删除桌面后缀
                table = table[:start]

                # 收到牌堆底部
                cur.extend(gained)
                # 收牌后当前玩家继续出牌，turn 不变
            else:
                # 没收牌则轮到对方
                turn ^= 1

            # 超过 10000 次仍未结束，判平局
            if moves > 10000:
                return 0 if not table else table[-1]
