```java
import java.util.*;

public class Solution {
    /**
     * 代码中的类名、方法名、参数名已经指定，请勿修改，直接返回方法规定的值即可
     *
     * @param cardA int整型一维数组 甲的牌序列
     * @param cardB int整型一维数组 乙的牌序列
     * @return int整型
     */
    public int catFishCardGame(int[] cardA, int[] cardB) {
        // 双方手牌队列
        Deque<Integer> a = new ArrayDeque<>();
        Deque<Integer> b = new ArrayDeque<>();
        for (int x : cardA) a.offerLast(x);
        for (int x : cardB) b.offerLast(x);

        // 桌面牌堆，按“从底到顶”存储
        List<Integer> table = new ArrayList<>();

        // pos[x] 维护点数 x 在桌面上的出现位置栈
        List<Integer>[] pos = new ArrayList[14];
        for (int i = 0; i < 14; i++) pos[i] = new ArrayList<>();

        int turn = 0;   // 0 表示甲，1 表示乙
        int moves = 0;  // 总出牌次数

        while (true) {
            Deque<Integer> cur = (turn == 0) ? a : b;
            Deque<Integer> other = (turn == 0) ? b : a;

            // 回合开始时无牌可出，游戏结束
            if (cur.isEmpty()) {
                if (!other.isEmpty()) {
                    return other.peekFirst();
                }
                return table.isEmpty() ? 0 : table.get(table.size() - 1);
            }

            // 出牌
            int x = cur.pollFirst();
            moves++;

            // 记录出牌前桌面是否非空，供 J 特效使用
            boolean hadTable = !table.isEmpty();

            int oldSame = pos[x].isEmpty() ? -1 : pos[x].get(pos[x].size() - 1);

            // 当前牌放到桌面顶端
            table.add(x);
            pos[x].add(table.size() - 1);

            boolean captured = false;
            int start = -1;

            // J 特效优先
            if (x == 11 && hadTable) {
                start = 0;
                captured = true;
            } else if (oldSame != -1) {
                // 普通同点数匹配
                start = oldSame;
                captured = true;
            }

            if (captured) {
                // 先保存要收走的牌
                List<Integer> gained = new ArrayList<>();
                for (int i = start; i < table.size(); i++) {
                    gained.add(table.get(i));
                }

                // 从后往前弹出位置栈
                for (int i = table.size() - 1; i >= start; i--) {
                    int v = table.get(i);
                    pos[v].remove(pos[v].size() - 1);
                }

                // 删除桌面后缀
                while (table.size() > start) {
                    table.remove(table.size() - 1);
                }

                // 收到当前玩家牌堆底部
                for (int v : gained) {
                    cur.offerLast(v);
                }
                // 收牌后当前玩家继续出牌
            } else {
                // 没收牌则交换回合
                turn ^= 1;
            }

            // 超过 10000 次仍未结束，判平局
            if (moves > 10000) {
                return table.isEmpty() ? 0 : table.get(table.size() - 1);
            }
        }
    }
}
