class Solution {
public:
    /**
     * 代码中的类名、方法名、参数名已经指定，请勿修改，直接返回方法规定的值即可
     *
     * @param cardA int整型vector 甲的牌序列
     * @param cardB int整型vector 乙的牌序列
     * @return int整型
     */
    int catFishCardGame(vector<int>& cardA, vector<int>& cardB) {
        // 双方手牌队列
        deque<int> a(cardA.begin(), cardA.end());
        deque<int> b(cardB.begin(), cardB.end());

        // 桌面牌堆，按“从底到顶”存储
        vector<int> table;

        // pos[x] 维护点数 x 在桌面上的出现位置栈
        vector<int> pos[14];

        int turn = 0;   // 0 表示甲，1 表示乙
        int moves = 0;  // 总出牌次数

        while (true) {
            deque<int>& cur = (turn == 0) ? a : b;
            deque<int>& other = (turn == 0) ? b : a;

            // 回合开始时无牌可出，游戏结束
            if (cur.empty()) {
                if (!other.empty()) {
                    return other.front();
                }
                return table.empty() ? 0 : table.back();
            }

            // 出牌
            int x = cur.front();
            cur.pop_front();
            moves++;

            // 记录出牌前桌面是否非空，供 J 特效判断
            bool hadTable = !table.empty();

            int oldSame = pos[x].empty() ? -1 : pos[x].back();

            // 放到桌面顶端
            table.push_back(x);
            pos[x].push_back((int)table.size() - 1);

            bool captured = false;
            int start = -1;

            // J 特效优先
            if (x == 11 && hadTable) {
                start = 0;
                captured = true;
            } else if (oldSame != -1) {
                // 普通同点数匹配
                start = oldSame;
                captured = true;
            }

            if (captured) {
                // 保存收走的牌，顺序保持为桌面从下到上
                vector<int> gained(table.begin() + start, table.end());

                // 从后往前同步弹出位置栈
                for (int i = (int)table.size() - 1; i >= start; i--) {
                    int v = table[i];
                    pos[v].pop_back();
                }

                // 删除桌面后缀
                table.resize(start);

                // 收到当前玩家牌堆底部
                for (int v : gained) {
                    cur.push_back(v);
                }
                // 收牌后当前玩家继续出牌
            } else {
                // 没收牌则换对手
                turn ^= 1;
            }

            // 超过 10000 次仍未结束，判平局
            if (moves > 10000) {
                return table.empty() ? 0 : table.back();
            }
        }
    }
};
