```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAXN 20010

int catFishCardGame(int* cardA, int cardASize, int* cardB, int cardBSize) {
    // 双方手牌队列（用数组模拟，ha/ta 为队首队尾）
    int* qa = (int*)malloc(MAXN * sizeof(int));
    int* qb = (int*)malloc(MAXN * sizeof(int));
    int ha = 0, ta = 0, hb = 0, tb = 0;

    for (int i = 0; i < cardASize; i++) qa[ta++] = cardA[i];
    for (int i = 0; i < cardBSize; i++) qb[tb++] = cardB[i];

    // 桌面牌堆，从底到顶
    int* table = (int*)malloc(MAXN * sizeof(int));
    int tsz = 0;

    // 每个点数在桌面的位置栈，用于 O(1) 查找
    int* pos[14];
    int posTop[14] = {0};
    for (int v = 0; v < 14; v++) pos[v] = (int*)malloc(MAXN * sizeof(int));

    int turn = 0;   // 0=甲, 1=乙
    int moves = 0;

    while (1) {
        int* curQ = (turn == 0) ? qa : qb;
        int* curH = (turn == 0) ? &ha : &hb;
        int* curT = (turn == 0) ? &ta : &tb;
        int* othQ = (turn == 0) ? qb : qa;
        int* othH = (turn == 0) ? &hb : &ha;

        // 回合开始无牌可出
        if (*curH >= *curT) {
            int result = (*othH < *(turn == 0 ? &tb : &ta)) ? othQ[*othH]
                                 : (tsz == 0 ? 0 : table[tsz - 1]);
            free(qa); free(qb); free(table);
            for (int v = 0; v < 14; v++) free(pos[v]);
            return result;
        }

        // 出牌
        int x = curQ[(*curH)++];
        moves++;

        bool hadTable = (tsz > 0);
        int oldSame = (posTop[x] > 0) ? pos[x][posTop[x] - 1] : -1;

        table[tsz] = x;
        pos[x][posTop[x]++] = tsz;
        tsz++;

        bool captured = false;
        int start = -1;

        // J(11) 特效优先
        if (x == 11 && hadTable) {
            start = 0;
            captured = true;
        } else if (oldSame != -1) {
            start = oldSame;
            captured = true;
        }

        if (captured) {
            // 同步弹出被收走牌的位置栈
            for (int i = tsz - 1; i >= start; i--) posTop[table[i]]--;
            // 收到的牌加入当前玩家队尾
            for (int i = start; i < tsz; i++) curQ[(*curT)++] = table[i];
            tsz = start;
        } else {
            turn ^= 1;  // 没收牌则切换回合
        }

        // 超过 10000 次判平局
        if (moves > 10000) {
            int result = (tsz == 0) ? 0 : table[tsz - 1];
            free(qa); free(qb); free(table);
            for (int v = 0; v < 14; v++) free(pos[v]);
            return result;
        }
    }
}
